from datetime import datetime, timezone, timedelta

CUT_OFF = datetime.now(timezone.utc) - timedelta(hours=24)

def parse_jira_datetime(value):
    if not value:
        return None

    s = str(value).strip()

    # Jira format examples:
    # 2026-06-20T14:43:25.006+0000
    # 2026-06-20T14:43:25.006Z
    if s.endswith("Z"):
        s = s[:-1] + "+00:00"

    # Convert +0000 -> +00:00
    if len(s) >= 5 and (s[-5] in ["+", "-"]) and s[-3] != ":":
        s = s[:-2] + ":" + s[-2:]

    try:
        dt = datetime.fromisoformat(s)
    except ValueError:
        return None

    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=timezone.utc)

    return dt.astimezone(timezone.utc)

def clean_text(value):
    if value is None:
        return ""
    return " ".join(str(value).split())

def format_worklog(wl):
    author = (wl.get("author") or {}).get("displayName") or (wl.get("author") or {}).get("name") or "Unknown"
    created = parse_jira_datetime(wl.get("created") or wl.get("updated") or wl.get("started"))
    comment = clean_text(wl.get("comment", ""))
    time_spent = wl.get("timeSpent", "")
    started = wl.get("started", "")

    return {
        "created": created.isoformat() if created else "",
        "author": author,
        "started": started,
        "timeSpent": time_spent,
        "timeSpentSeconds": wl.get("timeSpentSeconds", 0),
        "comment": comment,
    }

def build_context(issue):
    fields = issue.get("fields", {})
    issue_key = issue.get("key", "")

    assignee = fields.get("assignee").get("name")


    worklogs = (fields.get("worklog") or {}).get("worklogs", [])
    recent_worklogs = []

    for wl in worklogs:
        ts = parse_jira_datetime(wl.get("updated") or wl.get("created") or wl.get("started"))
        if ts and ts >= CUT_OFF:
            recent_worklogs.append((ts, wl))

    recent_worklogs.sort(key=lambda x: x[0])

    lines = [
        f"Issue Key: {issue_key}",
        "Worklogs from the last 24 hours:",
    ]

    formatted_worklogs = []
    if recent_worklogs:
        for ts, wl in recent_worklogs:
            fw = format_worklog(wl)
            formatted_worklogs.append(fw)
            lines.append(
                f"- {fw['created']} | {fw['author']} | {fw['timeSpent']} | {fw['comment']}"
            )
    else:
        lines.append("None")

    return issue_key, "\n".join(lines), formatted_worklogs, assignee

