merged = {}

for item in _items:
    issue = item.get("json", {})
    key = issue.get("key")
    if not key:
        continue

    if key not in merged:
        merged[key] = issue
    else:
        existing = merged[key]
        existing_fields = existing.setdefault("fields", {})
        existing_worklog = existing_fields.setdefault("worklog", {}).setdefault("worklogs", [])

        seen_ids = {w.get("id") for w in existing_worklog}
        incoming_worklogs = (issue.get("fields") or {}).get("worklog", {}).get("worklogs", [])

        for wl in incoming_worklogs:
            if wl.get("id") not in seen_ids:
                existing_worklog.append(wl)
                seen_ids.add(wl.get("id"))

output_items = []

for key, issue in merged.items():
    issue_key, context_text, recent_worklogs, assignee = build_context(issue)

    output_items.append({
        "json": {
            "sprint_id" : "",
            "assignee" : assignee,
            "issue_key": issue_key,
            "user_message": context_text,
            "recent_worklogs": recent_worklogs,
            "recent_worklog_count": len(recent_worklogs),
        }
    })

return output_items

